select count(*) from postgres.comments as c, postgres.posts as p, postgres.posthistory as ph, postgres.badges as b, postgres.users as u where u.id = c.userid and u.id = p.owneruserid and u.id = ph.userid and u.id = b.userid and p.posttypeid=1 and p.score<=35 and p.answercount=1 and p.commentcount<=17 and p.favoritecount>=0 and b."date">=timestamp '2010-07-27 17:58:45' and b."date"<=timestamp '2014-09-06 17:33:22' and u.views<=233 and u.downvotes<=2 and u.creationdate>=timestamp '2010-09-16 16:00:55' and u.creationdate<=timestamp '2014-08-24 21:12:02';
